// Knowledge Center Batch 4 — 46 articles to bring total from 54 to 100
import type { KnowledgeArticle } from "./knowledge-articles";

export const KNOWLEDGE_BATCH4: Record<string, KnowledgeArticle> = {
  // ── DEFINITIONS: more solvent/reagent types ───────────────
  "what-is-reagent-grade": { slug: "what-is-reagent-grade", title: "What Is Reagent Grade?", h1: "What Is Reagent Grade?", category: "definitions",
    excerpt: "Reagent grade meets ACS (American Chemical Society) specifications for general laboratory use — a lower bar than HPLC or LC-MS grade.",
    seoDescription: "Reagent grade (ACS grade) explained: what it tests for, how it compares to HPLC and LC-MS grade, and when it's sufficient.",
    content: [{ type: "p", text: "Reagent grade (often labeled ACS grade) meets the purity specifications published by the American Chemical Society for general laboratory chemical use. These specifications focus on overall assay purity, heavy metal limits, and a selection of named impurity tests — but they're not designed around the specific requirements of chromatographic or spectroscopic analysis, which is why reagent grade is generally not recommended as an HPLC mobile phase component despite being 'high purity' in a general sense." }, { type: "h2", text: "When reagent grade is appropriate" }, { type: "list", items: ["General bench chemistry, sample preparation steps that don't touch the detector", "Cleaning glassware and equipment", "Reactions where chromatographic-grade purity isn't required", "Cost-sensitive applications where the purity difference genuinely doesn't affect results"] }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["solvent-grade-comparison-chart", "what-is-hplc-grade-ethanol"] },
  "what-is-technical-grade": { slug: "what-is-technical-grade", title: "What Is Technical Grade Solvent?", h1: "What Is Technical Grade?", category: "definitions",
    excerpt: "Technical grade is the lowest purity tier — suitable for industrial processes and cleaning, but never for analytical work.",
    seoDescription: "Technical grade solvent explained: what it lacks compared to reagent or HPLC grade, and appropriate vs inappropriate uses.",
    content: [{ type: "p", text: "Technical grade (also called industrial grade or commercial grade) is solvent manufactured for industrial processes — cleaning, degreasing, extraction at scale — where precise chemical purity isn't a concern. It's not tested against analytical-grade specifications and may contain significant levels of impurities that would be unacceptable in any laboratory application involving a detector. The per-liter cost is substantially lower than any analytical grade, which is why it's sometimes tempting to substitute — but the risk of method interference or contamination makes this inappropriate for any use that touches an analytical instrument." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-reagent-grade", "solvent-grade-comparison-chart"] },
  "what-is-excipient": { slug: "what-is-excipient", title: "What Is A Pharmaceutical Excipient?", h1: "What Is An Excipient?", category: "definitions",
    excerpt: "Excipients are inactive ingredients in drug products — binders, fillers, solvents, and preservatives that must meet pharmacopeial quality standards.",
    seoDescription: "Pharmaceutical excipient explained: what excipients do in drug formulation, quality requirements, and common examples like glycerol and PEG.",
    content: [{ type: "p", text: "A pharmaceutical excipient is any inactive ingredient in a drug product — the components that aren't the active pharmaceutical ingredient (API) but that are essential for the product's physical form, stability, bioavailability, or patient acceptability. Common excipient categories include binders (holding tablets together), fillers (providing bulk), solvents (dissolving or suspending the API), preservatives, and coating agents." }, { type: "h2", text: "Quality requirements" }, { type: "p", text: "Excipients must meet pharmacopeial monograph specifications (USP-NF, EP, or both) and comply with ICH Q3D for elemental impurities and ICH Q3C for residual solvents — the same regulatory framework that governs the API itself, because excipient impurities end up in the final drug product just as surely as API impurities do." }, { type: "product-links", categories: ["excipients", "pharma-grade"] }],
    relatedArticles: ["what-is-pharma-grade-solvent", "what-is-ich-q3d"] },
  "what-is-food-grade-chemical": { slug: "what-is-food-grade-chemical", title: "What Is A Food Grade Chemical?", h1: "What Is Food Grade?", category: "definitions",
    excerpt: "Food grade means a chemical meets FCC (Food Chemicals Codex) specifications for use in food and beverage manufacturing.",
    seoDescription: "Food grade chemical explained: FCC specifications, kosher/halal certification, and how food grade differs from pharma grade.",
    content: [{ type: "p", text: "A food grade chemical meets the specifications published in the Food Chemicals Codex (FCC) for use as a food ingredient, processing aid, or additive. FCC specifications define purity, identity tests, and specific impurity limits relevant to food safety — a different testing panel than pharmaceutical (USP/EP) specifications, though there's significant overlap for many materials that are used in both food and pharmaceutical applications." }, { type: "h2", text: "Kosher and halal certification" }, { type: "p", text: "Many food-grade chemical buyers require kosher and/or halal certification in addition to FCC compliance — these are process certifications governing how the material was manufactured and handled, not additional purity specifications, but they're often a hard requirement for food manufacturers selling into markets where these certifications matter." }, { type: "product-links", categories: ["food-grade", "excipients"] }],
    relatedArticles: ["what-is-pharma-grade-solvent", "what-is-coa"] },
  "what-is-cas-number": { slug: "what-is-cas-number", title: "What Is A CAS Number?", h1: "What Is A CAS Number?", category: "definitions",
    excerpt: "A CAS Registry Number uniquely identifies a chemical substance worldwide — the universal identifier that eliminates ambiguity between naming conventions.",
    seoDescription: "CAS number explained: what it identifies, how to use it, and why it matters more than chemical names for precise ordering.",
    content: [{ type: "p", text: "A CAS (Chemical Abstracts Service) Registry Number is a unique numerical identifier assigned to every chemical substance described in the open scientific literature. Unlike chemical names — which can vary between IUPAC nomenclature, common names, trade names, and regional conventions — a CAS number is unambiguous: CAS 67-56-1 is methanol everywhere, regardless of whether someone calls it methanol, methyl alcohol, carbinol, or wood alcohol." }, { type: "h2", text: "Why CAS numbers matter for purchasing" }, { type: "p", text: "When ordering solvents internationally, specifying the CAS number alongside the product name eliminates the risk of miscommunication between naming conventions — particularly important when the buyer and supplier speak different languages or use different regional naming traditions for the same chemical." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-coa", "what-is-un-number"] },
  "what-is-reagent-kit": { slug: "what-is-reagent-kit", title: "What Is A Reagent Kit?", h1: "What Is A Reagent Kit?", category: "definitions",
    excerpt: "A reagent kit bundles multiple components for a specific analytical workflow into a single, pre-qualified order — reducing sourcing complexity and batch-matching risk.",
    seoDescription: "Reagent kit explained: what's included, how kits simplify purchasing and documentation, and common kit types for HPLC and QC workflows.",
    content: [{ type: "p", text: "A reagent kit packages multiple reagents, consumables, and (sometimes) reference standards needed for a specific analytical workflow into a single SKU — ordered, shipped, and documented as one unit rather than assembled from separate purchase orders with separate lot numbers and separate CoAs. The value is in workflow integration: every component in the kit has been selected and tested for compatibility with the specific method, eliminating the qualification work a lab would otherwise need to do when sourcing each component independently." }, { type: "product-links", categories: ["reagent-kits"] }],
    relatedArticles: ["what-is-coa"] },
  // ── TECHNIQUE: detection methods ──────────────────────────
  "what-is-fluorescence-detection": { slug: "what-is-fluorescence-detection", title: "What Is Fluorescence Detection In HPLC?", h1: "What Is Fluorescence Detection?", category: "technique",
    excerpt: "Fluorescence detection offers 10-100× greater sensitivity than UV for compounds that fluoresce — but only a subset of analytes qualify.",
    seoDescription: "HPLC fluorescence detection explained: how it works, sensitivity advantage over UV, and solvent purity requirements.",
    content: [{ type: "p", text: "Fluorescence detection excites a compound at one wavelength and measures the emitted light at a longer wavelength. Because only fluorescent compounds generate signal (and background fluorescence from the mobile phase is typically very low), fluorescence detection offers 10-100× greater sensitivity than UV absorption for compounds that fluoresce — but it's limited to compounds with inherent fluorescence or that can be derivatized to add a fluorescent tag." }, { type: "h2", text: "Solvent considerations" }, { type: "p", text: "Most HPLC grade solvents are adequate for fluorescence detection, since fluorescent contaminants are relatively uncommon in well-purified solvents. However, some lower-grade solvents can carry trace fluorescent impurities (particularly certain aromatic compounds) that show up as elevated background specifically on a fluorescence detector while being invisible to UV — worth testing if unexplained background appears on a fluorescence method after a solvent change." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-spectroscopic-grade-solvent", "hplc-solvent-selection-guide"] },
  "what-is-refractive-index-detection": { slug: "what-is-refractive-index-detection", title: "What Is Refractive Index (RI) Detection?", h1: "What Is RI Detection?", category: "technique",
    excerpt: "RI detection is universal but not very sensitive — it responds to any compound that changes the mobile phase's refractive index, making it the fallback for non-UV-absorbing analytes.",
    seoDescription: "Refractive index detection in HPLC explained: how it works, sensitivity limitations, and why gradient elution is incompatible.",
    content: [{ type: "p", text: "Refractive index detection measures the difference in refractive index between the column eluent (containing analyte) and a reference cell of pure mobile phase. It's a universal detector — any compound that changes the refractive index will produce a signal — but it's also one of the least sensitive HPLC detectors and is inherently incompatible with gradient elution (since the changing mobile phase composition continuously changes the baseline refractive index)." }, { type: "h2", text: "Common uses" }, { type: "list", items: ["Sugar analysis — glucose, fructose, sucrose, etc. have no UV chromophore", "Polymer molecular weight distribution (GPC/SEC)", "Organic acid analysis where UV sensitivity is insufficient"] }, { type: "product-links", categories: ["hplc-solvents", "mobile-phase-bags"] }],
    relatedArticles: ["hplc-solvent-selection-guide"] },
  "what-is-headspace-gc": { slug: "what-is-headspace-gc", title: "What Is Headspace GC?", h1: "What Is Headspace GC?", category: "technique",
    excerpt: "Headspace GC samples the gas phase above a heated sample rather than injecting the liquid directly — ideal for volatile analytes in complex matrices.",
    seoDescription: "Headspace GC explained: how it works, residual solvent testing applications, and advantages over direct liquid injection.",
    content: [{ type: "p", text: "Headspace GC analysis involves heating a sample in a sealed vial and sampling the vapor (headspace) above it, rather than injecting the liquid sample directly. Volatile compounds partition into the headspace in proportion to their concentration and volatility, and the headspace gas is then injected into the GC column for separation and detection. This eliminates most non-volatile matrix interference from ever reaching the column." }, { type: "h2", text: "Key application: residual solvent testing" }, { type: "p", text: "Headspace GC is the standard technique for ICH Q3C residual solvent testing in pharmaceutical materials — measuring trace levels of manufacturing solvents (methanol, acetone, dichloromethane, etc.) remaining in a drug substance or excipient after drying. The pharmacopeial method (USP <467>) specifies headspace injection specifically because it avoids the non-volatile matrix interference that direct injection would introduce." }, { type: "product-links", categories: ["gc-solvents", "pharma-grade"] }],
    relatedArticles: ["what-is-gc", "what-is-ich-q3c"] },
  "what-is-ion-chromatography": { slug: "what-is-ion-chromatography", title: "What Is Ion Chromatography (IC)?", h1: "What Is Ion Chromatography?", category: "technique",
    excerpt: "IC separates and quantifies ionic species (anions and cations) using ion-exchange columns and conductivity detection.",
    seoDescription: "Ion chromatography explained: anion and cation analysis, conductivity detection, and eluent/standard solution requirements.",
    content: [{ type: "p", text: "Ion chromatography (IC) is a form of liquid chromatography that separates ionic species — fluoride, chloride, nitrate, sulfate, and other common anions, or sodium, potassium, calcium, ammonium, and other cations — using ion-exchange columns and conductivity detection. It's the standard technique for water quality analysis (drinking water, wastewater, process water) and for counter-ion quantitation in pharmaceutical salts." }, { type: "h2", text: "Eluent and standard requirements" }, { type: "list", items: ["Eluents (mobile phases) are typically dilute solutions of sodium hydroxide, sodium carbonate, or methanesulfonic acid — specific to the column chemistry", "Certified anion and cation standard solutions are used for calibration, typically at 1000mg/L stock concentration", "Water purity is critical — TOC and ionic contamination in the water used for eluent preparation directly affect baseline and sensitivity"] }, { type: "product-links", categories: ["standard-solutions"] }],
    relatedArticles: ["what-is-aas", "what-is-icp-ms"] },
  // ── TECHNIQUE: method validation terms ────────────────────
  "what-is-method-validation": { slug: "what-is-method-validation", title: "What Is Analytical Method Validation?", h1: "What Is Method Validation?", category: "technique",
    excerpt: "Method validation proves that an analytical procedure reliably measures what it claims to measure — a regulatory requirement, not optional quality improvement.",
    seoDescription: "Analytical method validation explained: ICH Q2 parameters (specificity, linearity, accuracy, precision, LOD, LOQ) and why solvent consistency matters.",
    content: [{ type: "p", text: "Analytical method validation is the documented process of demonstrating that an analytical procedure is suitable for its intended use — that it measures the right thing (specificity), at the right sensitivity (LOD/LOQ), with acceptable accuracy (trueness), precision (repeatability and reproducibility), and linearity across the relevant concentration range. For pharmaceutical methods, ICH Q2(R2) defines the validation parameters; for other industries, equivalent frameworks (AOAC, ISO 17025) apply." }, { type: "h2", text: "Why solvent quality is a validation concern" }, { type: "p", text: "A method validated with one solvent supplier's material is implicitly validated against that supplier's impurity profile. Changing solvents after validation without confirming equivalence risks invalidating the validation — not because the method itself changed, but because an uncontrolled variable (solvent background) changed underneath it." }, { type: "product-links", categories: ["hplc-solvents", "standard-solutions"] }],
    relatedArticles: ["what-is-system-suitability", "what-is-limit-of-detection"] },
  "what-is-system-suitability": { slug: "what-is-system-suitability", title: "What Is System Suitability Testing (SST)?", h1: "What Is System Suitability?", category: "technique",
    excerpt: "SST confirms the chromatographic system is performing adequately before sample analysis begins — the gatekeeper between setup and data collection.",
    seoDescription: "System suitability testing explained: resolution, tailing factor, plate count, RSD, and how SST failure points to system vs solvent problems.",
    content: [{ type: "p", text: "System suitability testing (SST) is a set of measurements performed before (and sometimes during) an analytical sequence to confirm that the chromatographic system — column, instrument, mobile phase, and all connections — is performing within defined acceptance criteria. Common SST parameters include resolution between critical peak pairs, peak tailing factor, theoretical plate count, injection precision (%RSD of replicate injections), and retention time reproducibility." }, { type: "h2", text: "SST failure as a diagnostic tool" }, { type: "p", text: "When SST fails, it's telling you that something about the system is out of specification before any sample data is collected — which is far better than discovering the problem after a full batch of samples has already been run. SST failure after a solvent lot change, specifically, points directly at the solvent as the variable worth investigating first." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-method-validation", "what-is-limit-of-detection"] },
  "what-is-limit-of-detection": { slug: "what-is-limit-of-detection", title: "What Is Limit of Detection (LOD)?", h1: "What Is LOD?", category: "technique",
    excerpt: "LOD is the lowest concentration an analytical method can reliably detect — distinguish from blank noise — without necessarily quantifying it accurately.",
    seoDescription: "Limit of detection (LOD) explained: signal-to-noise approach, statistical approach, and how solvent background directly affects achievable LOD.",
    content: [{ type: "p", text: "The limit of detection (LOD) is the lowest analyte concentration that can be reliably distinguished from the absence of that analyte (blank signal or baseline noise) under stated conditions. It's a qualitative threshold — 'can we see it?' — distinct from the limit of quantitation (LOQ), which is the lowest concentration that can be measured with acceptable accuracy and precision." }, { type: "h2", text: "How solvent quality directly affects LOD" }, { type: "p", text: "LOD is typically defined relative to baseline noise (e.g. signal-to-noise ratio ≥ 3:1). Noisier baseline = higher LOD = less sensitive method. Since solvent background is a direct contributor to baseline noise, using a higher-purity solvent (or a grade specifically tested for the relevant detection mode) literally lowers the achievable LOD — it's one of the cheapest ways to improve method sensitivity without changing the instrument or the method itself." }, { type: "product-links", categories: ["lcms-solvents", "hplc-solvents"] }],
    relatedArticles: ["what-is-limit-of-quantitation", "what-is-method-validation"] },
  "what-is-limit-of-quantitation": { slug: "what-is-limit-of-quantitation", title: "What Is Limit of Quantitation (LOQ)?", h1: "What Is LOQ?", category: "technique",
    excerpt: "LOQ is the lowest concentration that can be measured with acceptable accuracy and precision — the practical lower boundary of your calibration curve.",
    seoDescription: "Limit of quantitation (LOQ) explained: how it differs from LOD, determination methods, and practical implications for method reporting.",
    content: [{ type: "p", text: "The limit of quantitation (LOQ) is the lowest analyte concentration at which quantitative results can be reported with an acceptable degree of accuracy and precision. It's higher than the LOD (which only requires detection, not accurate measurement) and defines the practical lower boundary of the calibration range — results below the LOQ can be reported as 'detected but below quantitation limit' but not as a specific numerical concentration." }, { type: "h2", text: "Common determination approaches" }, { type: "list", items: ["Signal-to-noise ratio ≥ 10:1 (a simple, widely used convention)", "Statistical approach based on the standard deviation of replicate blank measurements × 10", "Precision-based approach: the lowest concentration at which %RSD of replicate measurements meets a defined criterion (often ≤20%)"] }, { type: "product-links", categories: ["standard-solutions"] }],
    relatedArticles: ["what-is-limit-of-detection", "what-is-method-validation"] },
  "what-is-linearity": { slug: "what-is-linearity", title: "What Is Linearity In Analytical Methods?", h1: "What Is Linearity?", category: "technique",
    excerpt: "Linearity confirms that detector response is proportional to analyte concentration across the relevant range — the foundation of quantitative calibration.",
    seoDescription: "Analytical linearity explained: calibration curves, R² values, residual analysis, and practical linearity range considerations.",
    content: [{ type: "p", text: "Linearity is the ability of an analytical method to produce results that are directly proportional to the concentration of the analyte within a defined range — the basis for quantitative calibration. A linear method means that doubling the analyte concentration doubles the detector response, within the method's validated concentration range. Linearity is typically demonstrated by analyzing a series of standard solutions at known concentrations, plotting response vs. concentration, and confirming that the relationship is linear (commonly assessed by the correlation coefficient R² ≥ 0.999 and by visual inspection of residuals)." }, { type: "product-links", categories: ["standard-solutions"] }],
    relatedArticles: ["what-is-method-validation", "what-is-limit-of-quantitation"] },
  "what-is-matrix-effect": { slug: "what-is-matrix-effect", title: "What Is Matrix Effect In LC-MS?", h1: "What Is Matrix Effect?", category: "technique",
    excerpt: "Matrix effect is the enhancement or suppression of ionization caused by co-eluting matrix components — one of the most common sources of quantitation error in LC-MS.",
    seoDescription: "Matrix effect in LC-MS explained: ion suppression and enhancement, how to detect and compensate for matrix effects.",
    content: [{ type: "p", text: "Matrix effect in LC-MS refers to the influence of co-eluting sample matrix components (lipids, proteins, salts, buffer components) on the ionization efficiency of the target analyte — either suppressing signal (ion suppression, more common) or enhancing it (ion enhancement). Unlike UV detection, where matrix components that don't absorb at the detection wavelength are essentially invisible, ESI ionization is a competitive process where anything in the droplet that can carry charge competes with the analyte for ionization." }, { type: "h2", text: "Why this matters for solvent selection" }, { type: "p", text: "Solvent-derived contaminants (trace metals, non-volatile residue, plasticizer leachates) contribute to matrix effect in the same way sample matrix does — they're present in the droplet and compete for ionization. This is one of the mechanistic reasons LC-MS grade solvent improves quantitative accuracy, not just detection limits: it reduces the baseline matrix effect contributed by the mobile phase itself." }, { type: "product-links", categories: ["lcms-solvents"] }],
    relatedArticles: ["what-is-lcms-grade-solvent", "lcms-solvent-selection-guide"] },
  "what-is-recovery": { slug: "what-is-recovery", title: "What Is Recovery In Analytical Chemistry?", h1: "What Is Recovery?", category: "technique",
    excerpt: "Recovery measures what percentage of a known amount of analyte is actually detected by the method — the ultimate test of whether your sample preparation loses material.",
    seoDescription: "Analytical recovery explained: how it's measured, acceptable ranges, and what low recovery tells you about sample preparation.",
    content: [{ type: "p", text: "Recovery is the percentage of a known amount of analyte that's detected after going through the complete analytical procedure — from sample preparation through detection. A recovery of 85% means that 15% of the analyte was lost somewhere in the process (extraction, cleanup, transfer steps), while a recovery of 100% means everything that went in came back out as measured signal. Perfect 100% recovery is rarely achieved in practice; the goal is consistent, well-characterized recovery that can be accounted for in the final result." }, { type: "h2", text: "Solvent's role in recovery" }, { type: "p", text: "The solvents used for extraction and cleanup directly affect recovery — a solvent that doesn't fully dissolve the analyte, or an SPE cartridge washed with a solvent that partially elutes the analyte prematurely, will produce low and variable recovery regardless of how good the downstream chromatographic analysis is." }, { type: "product-links", categories: ["gc-solvents", "spe-products"] }],
    relatedArticles: ["what-is-spe", "what-is-method-validation"] },
  // ── COMPLIANCE: more frameworks ───────────────────────────
  "what-is-pharmacopoeia": { slug: "what-is-pharmacopoeia", title: "What Is A Pharmacopoeia?", h1: "What Is A Pharmacopoeia?", category: "compliance",
    excerpt: "A pharmacopoeia is an official, legally enforceable compendium of quality standards for medicines and their ingredients — USP and EP are the two most widely referenced.",
    seoDescription: "Pharmacopoeia explained: what it contains, USP vs EP vs JP, and how monograph specifications drive solvent and reagent quality requirements.",
    content: [{ type: "p", text: "A pharmacopoeia is an officially recognized collection of standards and specifications for the quality of medicines, pharmaceutical ingredients, and related materials — published by a national or international authority and enforceable by regulation. The most widely referenced pharmacopoeias globally are the United States Pharmacopeia (USP), the European Pharmacopoeia (EP/Ph. Eur.), and the Japanese Pharmacopoeia (JP). Each publishes individual monographs defining the identity, purity, and quality tests for specific materials, including solvents and reagents used in pharmaceutical manufacturing and testing." }, { type: "product-links", categories: ["pharma-grade"] }],
    relatedArticles: ["what-is-pharma-grade-solvent", "what-is-gmp"] },
  "what-is-supplier-qualification": { slug: "what-is-supplier-qualification", title: "What Is Supplier Qualification?", h1: "What Is Supplier Qualification?", category: "compliance",
    excerpt: "Supplier qualification is the documented process of evaluating and approving a vendor before using their materials — a formal quality system requirement, not just good practice.",
    seoDescription: "Supplier qualification explained: what it involves, documentation requirements, and how it applies to laboratory solvent suppliers.",
    content: [{ type: "p", text: "Supplier qualification is the formal process of evaluating a vendor's ability to consistently provide materials that meet your specified quality requirements — including reviewing their quality system, assessing their manufacturing capability, verifying documentation practices, and (in some regulatory frameworks) conducting an on-site audit. Once qualified, a supplier is placed on an approved supplier list and subject to periodic re-evaluation to confirm continued compliance." }, { type: "h2", text: "What qualification typically involves" }, { type: "list", items: ["Review of the supplier's quality certifications (ISO 9001, GMP, etc.)", "Assessment of CoA quality and completeness for recent production lots", "Evaluation of change notification and complaint handling processes", "Material testing — comparing the supplier's material against your specifications", "For regulated industries: on-site audit or documented questionnaire review"] }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-gmp", "what-is-coa", "what-is-iso-17025"] },
  "what-is-change-control": { slug: "what-is-change-control", title: "What Is Change Control?", h1: "What Is Change Control?", category: "compliance",
    excerpt: "Change control is the formal process for evaluating, approving, and documenting changes to validated processes or materials — preventing uncontrolled variation from entering a quality system.",
    seoDescription: "Change control explained: why it matters for laboratory reagent and solvent management, and how supplier changes trigger the process.",
    content: [{ type: "p", text: "Change control is a quality system process that requires any proposed change to a validated process, method, material, or system to be formally evaluated for its potential impact, approved before implementation, and documented after completion. In a laboratory context, this includes changes to solvent suppliers, solvent grades, instrument configurations, column types, and method parameters — any variable that could affect the validity of analytical results." }, { type: "h2", text: "Supplier changes and change control" }, { type: "p", text: "Changing a solvent or reagent supplier on a validated method is a change control event in any regulated quality system — not because the chemistry necessarily changes, but because an uncontrolled variable (the supplier's specific impurity profile, manufacturing process, and documentation practices) has changed. Documenting the equivalence assessment before making the switch is both a regulatory expectation and practical insurance against having to explain a performance shift retrospectively." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-supplier-qualification", "what-is-gmp"] },
  "what-is-batch-traceability": { slug: "what-is-batch-traceability", title: "What Is Batch Traceability?", h1: "What Is Batch Traceability?", category: "compliance",
    excerpt: "Batch traceability means being able to trace every material used in an analysis back to its specific manufacturing lot — the backbone of quality investigation and recall capability.",
    seoDescription: "Batch traceability explained: lot numbers, CoA records, and why traceability matters for laboratory reagents and solvents.",
    content: [{ type: "p", text: "Batch traceability is the ability to trace any material — solvent, reagent, standard, consumable — used in a specific analysis or manufacturing step back to its specific manufacturing lot, including the supplier, the lot-specific CoA, and (ideally) the date it was received, opened, and used. In the event of a quality investigation ('why did this batch of samples give unexpected results?'), traceability is what allows you to check whether a specific lot of solvent or reagent might be implicated." }, { type: "h2", text: "Practical implementation" }, { type: "p", text: "The simplest effective traceability system records the lot number from every bottle when it's put into service (many labs use a logbook or electronic record at the point of use) and retains CoAs in a searchable archive indexed by lot number. This minimal system takes seconds per bottle to maintain and provides most of the investigative value that more complex tracking systems do." }, { type: "product-links", categories: ["standard-solutions"] }],
    relatedArticles: ["what-is-coa", "what-is-gmp", "what-is-glp"] },
  // ── DEFINITIONS: more chromatography terms ────────────────
  "what-is-size-exclusion-chromatography": { slug: "what-is-size-exclusion-chromatography", title: "What Is Size Exclusion Chromatography (SEC/GPC)?", h1: "What Is Size Exclusion Chromatography?", category: "definitions",
    excerpt: "SEC separates molecules by size rather than chemical interaction — used for polymer molecular weight distribution and protein aggregate analysis.",
    seoDescription: "Size exclusion chromatography (SEC/GPC) explained: how size-based separation works, typical mobile phases, and RI vs UV detection.",
    content: [{ type: "p", text: "Size exclusion chromatography (SEC, also called gel permeation chromatography or GPC when applied to synthetic polymers) separates molecules based on their hydrodynamic size — larger molecules elute first because they can't enter the column packing's pores and pass through the column faster, while smaller molecules enter the pores and are retained longer. There's no chemical interaction driving the separation; it's purely a size-filtration mechanism." }, { type: "h2", text: "Common applications" }, { type: "list", items: ["Polymer molecular weight distribution (GPC)", "Protein aggregate analysis in biopharmaceuticals", "Polysaccharide characterization", "Natural product molecular weight profiling"] }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-reversed-phase-hplc"] },
  "what-is-column-dead-volume": { slug: "what-is-column-dead-volume", title: "What Is Column Dead Volume?", h1: "What Is Column Dead Volume?", category: "definitions",
    excerpt: "Dead volume is the volume of mobile phase in the column that's not interacting with the stationary phase — the void through which unretained compounds travel.",
    seoDescription: "Column dead volume explained: how it's measured, what it means for retention factor calculations, and its effect on resolution.",
    content: [{ type: "p", text: "Column dead volume (also called void volume, V0 or Vm) is the total volume of mobile phase inside the column that doesn't interact with the stationary phase — essentially the empty space between and within the packed particles. An unretained compound (one that has zero interaction with the stationary phase) elutes at the dead volume, and this elution time (the dead time, t0) serves as the reference point for calculating retention factors (k) for all other compounds in the separation." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-reversed-phase-hplc", "what-is-gradient-elution"] },
  "what-is-retention-factor": { slug: "what-is-retention-factor", title: "What Is Retention Factor (k)?", h1: "What Is Retention Factor?", category: "definitions",
    excerpt: "The retention factor describes how strongly a compound interacts with the stationary phase relative to the mobile phase — the fundamental measure of chromatographic retention.",
    seoDescription: "Retention factor (k) explained: how it's calculated, what it tells you about a separation, and how mobile phase composition controls it.",
    content: [{ type: "p", text: "The retention factor (k, sometimes written k') for a compound is calculated as (tR - t0) / t0, where tR is the compound's retention time and t0 is the column dead time. It represents how much longer the compound spends interacting with the stationary phase than it spends in the mobile phase — a k of 5 means the compound spends five times as long on the stationary phase as in the mobile phase." }, { type: "h2", text: "Why retention factor matters" }, { type: "p", text: "Retention factor is more useful than raw retention time for comparing separations across different systems, because it normalizes out column dimensions and flow rate. A compound with k = 5 on a 150mm column at 1 mL/min and on a 250mm column at 0.5 mL/min has different absolute retention times but the same fundamental interaction with the chromatographic system — the k value captures that underlying equivalence." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-column-dead-volume", "what-is-reversed-phase-hplc"] },
  "what-is-peak-tailing": { slug: "what-is-peak-tailing", title: "What Is Peak Tailing?", h1: "What Is Peak Tailing?", category: "definitions",
    excerpt: "Peak tailing is asymmetric peak shape where the back edge extends further than the front — a common chromatographic problem with specific, diagnosable causes.",
    seoDescription: "Peak tailing in HPLC explained: causes (secondary interactions, dead volume, column degradation), tailing factor calculation, and remedies.",
    content: [{ type: "p", text: "Peak tailing occurs when a chromatographic peak is asymmetric, with the trailing (right) edge extending further from the peak center than the leading edge — producing a shape that tails to the right rather than forming a symmetric Gaussian profile. It's quantified by the tailing factor (T), defined as the ratio of the back half-width to the front half-width at a defined peak height (typically 5% of peak height). A perfectly symmetric peak has T = 1.0; tailing peaks have T > 1.0." }, { type: "h2", text: "Common causes" }, { type: "list", items: ["Secondary interactions between basic analytes and residual silanols on the column surface", "Extra-column dead volume from poorly fitted connections, large-bore tubing, or oversized detector flow cells", "Column degradation from accumulated contamination or chemical damage to the stationary phase", "Mobile phase pH not adequately suppressing ionization of the analyte or the stationary phase"] }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-system-suitability", "what-is-method-validation"] },
  "what-is-resolution-chromatography": { slug: "what-is-resolution-chromatography", title: "What Is Resolution In Chromatography?", h1: "What Is Chromatographic Resolution?", category: "definitions",
    excerpt: "Resolution measures how well two adjacent peaks are separated — the ultimate metric of whether a separation is actually working.",
    seoDescription: "Chromatographic resolution explained: how it's calculated, minimum acceptable values, and the three factors that control it.",
    content: [{ type: "p", text: "Resolution (Rs) in chromatography quantifies how well two adjacent peaks are separated from each other, defined as the difference in retention times divided by the average of their peak widths. An Rs of 1.5 or greater represents baseline separation (peaks fully separated with baseline between them); Rs of 1.0 means the peaks are partially overlapping; below 1.0, quantitative accuracy for either peak is increasingly compromised." }, { type: "h2", text: "The three factors controlling resolution" }, { type: "list", items: ["Efficiency (N) — related to column length and particle size; higher N = sharper peaks", "Selectivity (α) — the ratio of retention factors for two compounds; controlled primarily by mobile phase composition and pH", "Retention (k) — controlled by organic modifier percentage; adequate retention (k > 2) is needed for resolution to be meaningful"] }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-system-suitability", "what-is-retention-factor"] },
  // ── MORE DEFINITIONS ──────────────────────────────────────
  "what-is-hptlc": { slug: "what-is-hptlc", title: "What Is HPTLC (High Performance TLC)?", h1: "What Is HPTLC?", category: "definitions",
    excerpt: "HPTLC uses smaller-particle TLC plates and automated sample application for higher resolution and semi-quantitative results than conventional TLC.",
    seoDescription: "HPTLC explained: how it improves on conventional TLC, typical applications in pharmaceutical and food analysis.",
    content: [{ type: "p", text: "High Performance Thin Layer Chromatography (HPTLC) uses TLC plates with smaller, more uniform particle size (typically 5µm vs 10-12µm for conventional TLC), combined with automated sample application (rather than manual spotting) and densitometric detection, to achieve significantly higher resolution and reproducibility than conventional TLC — bridging the gap between quick qualitative TLC and fully instrumental HPLC for applications where throughput and cost matter." }, { type: "product-links", categories: ["tlc-products"] }],
    relatedArticles: ["what-is-tlc"] },
  "what-is-flash-chromatography": { slug: "what-is-flash-chromatography", title: "What Is Flash Chromatography?", h1: "What Is Flash Chromatography?", category: "definitions",
    excerpt: "Flash chromatography uses compressed gas or pumps to drive solvent through a packed column — a faster, larger-scale alternative to gravity column chromatography for purification.",
    seoDescription: "Flash chromatography explained: how it differs from gravity columns and preparative HPLC, and typical solvent requirements.",
    content: [{ type: "p", text: "Flash chromatography is a purification technique that uses compressed air or a pump to push solvent through a short, wide column packed with silica gel — faster than gravity-driven column chromatography (minutes instead of hours) and simpler and cheaper than preparative HPLC. It's widely used in medicinal chemistry and natural products research for purifying milligram-to-gram quantities of material from reaction mixtures or crude extracts." }, { type: "h2", text: "Solvent considerations" }, { type: "p", text: "Flash chromatography typically uses technical or reagent grade solvents (hexane/ethyl acetate or DCM/methanol gradients are common) rather than HPLC grade, since the downstream detection is usually UV at a single wavelength or simply visual (watching colored bands), and the fractions collected are typically evaporated and re-analyzed by analytical methods anyway." }, { type: "product-links", categories: ["prep-solvents"] }],
    relatedArticles: ["what-is-preparative-hplc", "what-is-normal-phase-hplc"] },
  // ── MORE TECHNIQUE ────────────────────────────────────────
  "what-is-sample-derivatization": { slug: "what-is-sample-derivatization", title: "What Is Sample Derivatization?", h1: "What Is Derivatization?", category: "technique",
    excerpt: "Derivatization chemically modifies an analyte to improve its detection, separation, or stability — common in GC and amino acid analysis.",
    seoDescription: "Sample derivatization explained: why analytes are derivatized, common reagents, and applications in GC and HPLC amino acid analysis.",
    content: [{ type: "p", text: "Derivatization is a sample preparation step in which a chemical reagent reacts with the target analyte to produce a derivative with improved analytical properties — typically improved volatility (for GC analysis of non-volatile compounds), improved UV or fluorescence detection sensitivity, or improved chromatographic behavior (better peak shape, better separation from matrix). Common examples include silylation for GC analysis of polar compounds, and OPA or FMOC derivatization for HPLC amino acid analysis." }, { type: "product-links", categories: ["gc-solvents", "standard-solutions"] }],
    relatedArticles: ["what-is-gc", "what-is-fluorescence-detection"] },
  "what-is-liquid-liquid-extraction": { slug: "what-is-liquid-liquid-extraction", title: "What Is Liquid-Liquid Extraction (LLE)?", h1: "What Is Liquid-Liquid Extraction?", category: "technique",
    excerpt: "LLE partitions analytes between two immiscible solvents — a classical sample preparation technique still widely used alongside SPE.",
    seoDescription: "Liquid-liquid extraction explained: partitioning principle, common solvent choices, and when LLE is preferred over SPE.",
    content: [{ type: "p", text: "Liquid-liquid extraction (LLE) separates analytes from a sample matrix by partitioning them between two immiscible liquid phases — typically an aqueous sample and an organic extraction solvent. Analytes that are more soluble in the organic phase transfer from the aqueous sample into the organic layer, which is then separated, concentrated (by evaporation), and analyzed. Common extraction solvents include dichloromethane, ethyl acetate, hexane, and MTBE, chosen based on the analyte's polarity and the desired selectivity." }, { type: "h2", text: "GC grade solvent for extraction" }, { type: "p", text: "Extraction solvents for analytical LLE should be at least GC grade (low residue on evaporation, no interfering peaks), since the solvent is concentrated during the evaporation step — any impurity in the solvent concentrates proportionally alongside the analyte." }, { type: "product-links", categories: ["gc-solvents"] }],
    relatedArticles: ["what-is-spe", "what-is-gc-grade-solvent"] },
  "what-is-calibration-curve": { slug: "what-is-calibration-curve", title: "What Is A Calibration Curve?", h1: "What Is A Calibration Curve?", category: "technique",
    excerpt: "A calibration curve relates known analyte concentrations to measured instrument responses — the quantitative bridge between a peak area and a number on a report.",
    seoDescription: "Calibration curve explained: how it's built, linear vs weighted regression, and why standard solution quality directly affects quantitative accuracy.",
    content: [{ type: "p", text: "A calibration curve is a plot of instrument response (peak area, absorbance, signal intensity) versus known analyte concentration, constructed by analyzing a series of standard solutions at defined concentrations. Once the relationship between response and concentration is established (typically by linear regression), unknown sample responses are read from the curve to determine their concentration. The accuracy of every quantitative result reported by the method depends directly on the accuracy of this calibration — which in turn depends on the accuracy of the standard solutions used to build it." }, { type: "product-links", categories: ["standard-solutions"] }],
    relatedArticles: ["what-is-linearity", "what-is-method-validation"] },
  "what-is-internal-standard": { slug: "what-is-internal-standard", title: "What Is An Internal Standard?", h1: "What Is An Internal Standard?", category: "technique",
    excerpt: "An internal standard is a known compound added to every sample at a fixed concentration — it corrects for sample preparation losses and detector variability.",
    seoDescription: "Internal standard explained: what it does, how to choose one, and why it's essential for quantitative LC-MS methods.",
    content: [{ type: "p", text: "An internal standard (IS) is a compound added at a known, fixed concentration to every sample, calibration standard, and blank in an analytical sequence. By reporting results as the ratio of analyte response to internal standard response (rather than the absolute analyte response alone), the method automatically corrects for any variability that affects both compounds equally — injection volume variation, extraction recovery differences between samples, detector sensitivity drift, and (in LC-MS) matrix-dependent ion suppression." }, { type: "h2", text: "Choosing an internal standard" }, { type: "list", items: ["Should be chemically similar to the analyte (similar retention, similar ionization in LC-MS)", "Must not be naturally present in any sample", "Isotope-labeled analogs (deuterated or 13C-labeled versions of the analyte) are ideal for LC-MS because they co-elute and co-ionize with the analyte", "Must be commercially available in certified purity"] }, { type: "product-links", categories: ["standard-solutions", "lcms-solvents"] }],
    relatedArticles: ["what-is-matrix-effect", "what-is-calibration-curve"] },
  // ── MOBILE-PHASE: more topics ─────────────────────────────
  "buffer-pka-reference-table": { slug: "buffer-pka-reference-table", title: "Buffer pKa Reference Table For HPLC", h1: "Buffer pKa Reference Table", category: "mobile-phase",
    excerpt: "A quick-reference table of common HPLC buffer systems with their pKa values, effective pH ranges, and detector compatibility.",
    seoDescription: "HPLC buffer pKa reference table: phosphate, acetate, formate, ammonium, citrate, TRIS — pKa values and LC-MS compatibility at a glance.",
    content: [{ type: "p", text: "This reference table lists the most commonly used HPLC buffer systems alongside their pKa values, effective buffering ranges (pKa ± 1 pH unit), and compatibility with mass spectrometry detection. Use it as a quick-lookup when selecting a buffer for method development — the primary selection criterion is matching your target pH to a buffer whose effective range covers it." }, { type: "list", items: ["Formic acid — pKa 3.75, effective range ~2.8-4.8, LC-MS compatible", "Acetic acid — pKa 4.76, effective range ~3.8-5.8, LC-MS compatible", "Phosphoric acid — pKa₁ 2.15, pKa₂ 7.20, pKa₃ 12.35, NOT LC-MS compatible", "Ammonium formate — pKa 3.75 (formate) / 9.25 (ammonium), LC-MS compatible", "Ammonium acetate — pKa 4.76 (acetate) / 9.25 (ammonium), LC-MS compatible", "Ammonium bicarbonate — pKa 6.35, 10.33, LC-MS compatible", "TRIS — pKa 8.06, limited LC-MS compatibility", "Triethylamine (TEA) — pKa 10.75, NOT LC-MS compatible"] }, { type: "product-links", categories: ["mobile-phase-bags", "standard-solutions"] }],
    relatedArticles: ["what-is-mobile-phase", "choosing-mobile-phase-additives"] },
  "how-to-degas-mobile-phase": { slug: "how-to-degas-mobile-phase", title: "How To Degas Mobile Phase: Methods Compared", h1: "How To Degas Mobile Phase", category: "mobile-phase",
    excerpt: "A practical comparison of degassing methods — vacuum filtration, sonication, helium sparging, and inline degassers — with pros and cons of each.",
    seoDescription: "HPLC mobile phase degassing methods compared: vacuum, ultrasonic, helium sparging, inline degasser — effectiveness, cost, and practical tips.",
    content: [{ type: "p", text: "Degassing removes dissolved gas (primarily nitrogen and oxygen) from mobile phase, preventing microbubble formation that causes baseline noise, irregular peak shapes, and pump cavitation. Several methods are available, differing in effectiveness, convenience, and cost — the right choice depends on your instrument configuration and how much residual dissolved gas your method can tolerate." }, { type: "h2", text: "Method comparison" }, { type: "list", items: ["Vacuum filtration — moderate effectiveness, convenient as it happens alongside required filtration, but not sufficient alone for sensitive methods", "Ultrasonic bath — good effectiveness, widely available, 10-15 minutes per bottle, but a batch process not a continuous one", "Helium sparging — very effective, but requires helium supply and adds operational complexity and cost", "Inline vacuum degasser (built into most modern HPLC systems) — very effective, continuous, no manual intervention — the standard for routine work if the system has one"] }, { type: "product-links", categories: ["mobile-phase-bags"] }],
    relatedArticles: ["mobile-phase-degassing", "how-to-prepare-mobile-phase"] },
  // ── SELECTION-GUIDES: more ────────────────────────────────
  "karl-fischer-reagent-selection-guide": { slug: "karl-fischer-reagent-selection-guide", title: "Karl Fischer Reagent Selection Guide", h1: "Karl Fischer Reagent Selection Guide", category: "selection-guides",
    excerpt: "Choosing between volumetric and coulometric KF methods, one-component vs two-component reagents, and matching the reagent system to your sample type.",
    seoDescription: "How to select Karl Fischer reagents: volumetric vs coulometric, one-component vs two-component, and sample-specific considerations.",
    content: [{ type: "p", text: "Karl Fischer reagent selection depends on three things: the expected water content of your samples (which determines whether volumetric or coulometric titration is appropriate), the sample matrix (which affects solvent compatibility and may require a specialized reagent formulation), and your titrator type (which determines the physical format of the reagent — one-component systems are simpler, two-component systems offer better stability and selectivity for difficult matrices)." }, { type: "h2", text: "Decision framework" }, { type: "list", items: ["Water content > 100ppm (0.01%): volumetric KF — simpler, faster, appropriate for most pharmaceutical and chemical QC", "Water content < 100ppm: coulometric KF — higher sensitivity, needed for very dry materials like anhydrous solvents and battery electrolytes", "Simple matrices (pure solvents, clean solutions): one-component reagent is usually sufficient", "Complex matrices (oils, fats, samples with interfering aldehydes or ketones): two-component reagent with a specialized solvent formulation"] }, { type: "product-links", categories: ["karl-fischer"] }],
    relatedArticles: ["what-is-karl-fischer-titration", "what-is-anhydrous-solvent"] },
  "tlc-developing-solvent-guide": { slug: "tlc-developing-solvent-guide", title: "TLC Developing Solvent Selection Guide", h1: "TLC Developing Solvent Guide", category: "selection-guides",
    excerpt: "How to choose and optimize a TLC developing solvent system — starting from Rf targets and adjusting polarity to achieve the separation you need.",
    seoDescription: "TLC developing solvent selection: common solvent systems by polarity, Rf optimization, and transitioning from TLC to HPLC methods.",
    content: [{ type: "p", text: "TLC developing solvent selection is guided by the same polarity-matching logic as HPLC mobile phase selection, but with faster iteration — a TLC run takes minutes, making it practical to screen several solvent systems in an afternoon. The goal is a developing solvent that gives your compound(s) of interest Rf values in the 0.2-0.5 range (enough retention to separate from the origin, but not so much that everything runs to the solvent front)." }, { type: "h2", text: "Common starting points" }, { type: "list", items: ["Non-polar compounds: hexane/ethyl acetate (start at 9:1, adjust ratio to increase or decrease Rf)", "Moderately polar compounds: dichloromethane/methanol (start at 95:5)", "Very polar compounds: ethyl acetate/methanol/water or n-butanol/acetic acid/water systems", "Alkaloids and basic compounds: add a drop of triethylamine or ammonia to suppress tailing on silica"] }, { type: "product-links", categories: ["tlc-products"] }],
    relatedArticles: ["what-is-tlc", "what-is-hptlc"] },
  // ── DEFINITIONS: more practical terms ─────────────────────
  "what-is-uv-cutoff": { slug: "what-is-uv-cutoff", title: "What Is UV Cutoff For HPLC Solvents?", h1: "What Is UV Cutoff?", category: "definitions",
    excerpt: "UV cutoff is the wavelength below which a solvent absorbs too strongly for reliable UV detection — the single most important spec on an HPLC grade solvent CoA.",
    seoDescription: "UV cutoff for HPLC solvents explained: how it's measured, typical values for common solvents, and why it determines your detection limit.",
    content: [{ type: "p", text: "UV cutoff is the wavelength below which a solvent's own UV absorbance exceeds a defined threshold (typically 1.0 AU/cm path length), making it unsuitable as a transparent mobile phase component for UV detection at or below that wavelength. A solvent with a UV cutoff of 205nm is transparent enough for detection at 210nm and above, but would contribute unacceptable background absorbance at 200nm — raising the baseline and degrading detection sensitivity for any analyte measured at or below the cutoff wavelength." }, { type: "h2", text: "Common UV cutoffs" }, { type: "list", items: ["Acetonitrile: ~190nm — usable across virtually the entire UV range", "Methanol: ~205nm — fine for most common detection wavelengths, limiting below 210nm", "Water: ~190nm — effectively transparent across the UV range", "IPA: ~205nm", "THF: ~212nm — more limiting than acetonitrile or methanol", "Ethyl acetate: ~256nm — significantly limits UV detection options", "Dichloromethane: ~233nm"] }, { type: "product-links", categories: ["hplc-solvents", "spectroscopic-solvents"] }],
    relatedArticles: ["what-is-hplc-grade-ethanol", "hplc-solvent-selection-guide"] },
  "what-is-non-volatile-residue": { slug: "what-is-non-volatile-residue", title: "What Is Non-Volatile Residue (NVR)?", h1: "What Is Non-Volatile Residue?", category: "definitions",
    excerpt: "NVR is what's left behind when a solvent evaporates — a direct measure of dissolved solid contamination that accumulates in your column and detector.",
    seoDescription: "Non-volatile residue in HPLC solvents explained: how it's measured, why it matters, and how it differs between HPLC and LC-MS grade.",
    content: [{ type: "p", text: "Non-volatile residue (NVR, sometimes called evaporation residue or residue on evaporation) is the mass of solid material remaining after a known volume of solvent is evaporated to dryness under controlled conditions. It represents dissolved contaminants — salts, polymer traces, non-volatile organic compounds — that don't leave with the solvent itself. In HPLC work, NVR accumulates in the column, in-line filters, and detector flow cell over repeated injections, gradually degrading system performance in a way that often gets misattributed to column aging rather than solvent quality." }, { type: "product-links", categories: ["hplc-solvents", "lcms-solvents"] }],
    relatedArticles: ["what-is-hplc-grade-ethanol", "solvent-grade-comparison-chart"] },
  "what-is-water-content-specification": { slug: "what-is-water-content-specification", title: "What Is Water Content Specification For Solvents?", h1: "What Is Water Content Specification?", category: "definitions",
    excerpt: "Water content in HPLC solvents is measured by Karl Fischer titration and affects UV transparency, mobile phase reproducibility, and normal-phase retention behavior.",
    seoDescription: "Solvent water content specification explained: why it's tested, how it's measured (Karl Fischer), and when it matters for your method.",
    content: [{ type: "p", text: "Water content specification on a solvent CoA indicates the maximum (or actual measured) amount of residual water in the solvent, determined by Karl Fischer titration. For most reversed-phase HPLC work, moderate water content (a few hundred ppm) in an organic solvent like acetonitrile or methanol has minimal practical impact, since the mobile phase already contains a substantial aqueous component. For normal-phase chromatography, anhydrous chemistry, or Karl Fischer titration itself, water content is a critical parameter because even small amounts of water directly interfere with the separation or measurement." }, { type: "product-links", categories: ["hplc-solvents", "anhydrous-solvents", "karl-fischer"] }],
    relatedArticles: ["what-is-karl-fischer-titration", "what-is-anhydrous-solvent"] },
  "what-is-assay-purity": { slug: "what-is-assay-purity", title: "What Is Assay (Purity) On A Solvent CoA?", h1: "What Is Assay Purity?", category: "definitions",
    excerpt: "Assay on a CoA reports the percentage of the labeled chemical actually present — typically determined by GC analysis, with everything else counted as impurities.",
    seoDescription: "Solvent assay (purity) explained: how it's measured by GC, what 99.9% actually means, and how to read this value on a CoA.",
    content: [{ type: "p", text: "The assay (or purity) value on a solvent Certificate of Analysis reports what percentage of the material is actually the labeled chemical — for example, an assay of 99.9% for acetonitrile means that 99.9% of the bottle's contents is acetonitrile and the remaining 0.1% is a combination of water and other trace impurities. Assay is typically determined by gas chromatography (GC-FID), where the solvent's own peak is compared against a reference standard and everything else detected is classified as impurity." }, { type: "h2", text: "What '99.9%' actually means in practice" }, { type: "p", text: "A 0.1% impurity level sounds tiny, but in a liter of solvent it's roughly 1mL of 'not the labeled compound' — distributed across potentially dozens of individual trace impurities, each at a different concentration. Whether this matters depends entirely on whether any of those specific impurities interfere with your particular detection method, which is why grade-specific testing (UV cutoff for HPLC grade, MS-blank for LC-MS grade) exists alongside the generic assay value." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-coa", "what-is-hplc-grade-ethanol"] },
  // ── GRADES category ───────────────────────────────────────
  "solvent-grades-explained": { slug: "solvent-grades-explained", title: "Laboratory Solvent Grades Explained: From Technical to Electronic", h1: "Solvent Grades Explained", category: "grades",
    excerpt: "A complete overview of laboratory solvent grade tiers — what each one tests for, who needs it, and the real cost-vs-purity tradeoff at each level.",
    seoDescription: "All laboratory solvent grades explained in one reference: technical, reagent, HPLC, gradient, UPLC, LC-MS, GC, spectroscopic, pharma, electronic, trace analysis.",
    content: [{ type: "p", text: "Laboratory solvents are sold at multiple purity tiers, each designed for a specific category of use and tested against a different impurity panel. The grade you need depends on your detection method and your method's sensitivity requirements — not on a general instinct that 'purer is always better.' Over-specifying wastes budget; under-specifying risks method failure. The right grade is the one that covers your method's actual sensitivity requirements without paying for testing your method will never exercise." }, { type: "h2", text: "The full grade hierarchy" }, { type: "list", items: ["Technical/industrial — cheapest, no analytical testing, for cleaning and industrial processes only", "Reagent/ACS — general lab purity, not chromatography-specific, suitable for bench chemistry", "HPLC grade — UV cutoff, NVR, water content tested, the standard for UV-detected HPLC", "Gradient grade — tighter UV and impurity matching between solvents for gradient methods", "UPLC grade — HPLC-level purity plus finer particulate filtration (0.1µm) for sub-2µm columns", "LC-MS grade — HPLC plus trace metals, MS-blank, for mass spec detection", "GC grade — residue on evaporation, GC purity check, for gas chromatography", "Spectroscopic grade — UV/Vis background absorbance across a wavelength range, for spectrophotometry", "Pharma (USP/EP) — pharmacopeial monograph testing, for pharmaceutical manufacturing and QC", "Electronic (SEMI) — sub-ppb metals, particle count, for semiconductor wafer processing", "Trace analysis — ultra-low metal content in digestion acids for ICP-MS"] }, { type: "product-links", categories: ["hplc-solvents", "lcms-solvents", "gc-solvents", "pharma-grade", "electronic-grade", "trace-analysis-grade"] }],
    relatedArticles: ["solvent-grade-comparison-chart", "hplc-vs-lcms-solvents"] },
  "when-to-upgrade-solvent-grade": { slug: "when-to-upgrade-solvent-grade", title: "When To Upgrade (or Downgrade) Your Solvent Grade", h1: "When To Change Solvent Grade", category: "grades",
    excerpt: "Practical decision criteria for when a grade change is worth the cost — and when the current grade is already the right choice.",
    seoDescription: "When to upgrade or downgrade HPLC/LC-MS solvent grade: decision criteria based on detection mode, method sensitivity, and budget.",
    content: [{ type: "p", text: "The question of whether to upgrade solvent grade usually arises when a method's sensitivity requirements change (moving from UV to LC-MS detection, for example), when unexplained background problems resist other troubleshooting, or when budget pressure prompts a look at whether the current grade is actually necessary. The question of downgrading comes up when someone realizes the lab has been paying for LC-MS grade on a method that only uses UV detection." }, { type: "h2", text: "Upgrade indicators" }, { type: "list", items: ["Adding MS detection to a method previously run with UV only → upgrade from HPLC to LC-MS grade", "Unexplained background that persists after column change and source cleaning → try a higher grade lot to see if the problem is solvent-related", "Moving to sub-2µm UPLC columns → ensure solvent is UPLC-grade filtered (0.1µm)", "LOD requirements tightened due to regulatory change → re-evaluate whether current grade achieves the new LOD target"] }, { type: "h2", text: "Downgrade indicators" }, { type: "list", items: ["Method uses only UV or RI detection with no mass spec → HPLC grade is sufficient, LC-MS grade is over-specified", "Method is preparative (purification), not analytical → prep grade is appropriate, HPLC grade is over-specified", "Solvent is used only for cleaning or rinse steps → reagent or even technical grade is sufficient"] }, { type: "product-links", categories: ["hplc-solvents", "lcms-solvents"] }],
    relatedArticles: ["solvent-grades-explained", "solvent-grade-comparison-chart"] },
  // ── FINAL 4 articles to reach 100 ─────────────────────────
  "what-is-reach": { slug: "what-is-reach", title: "What Is REACH Regulation?", h1: "What Is REACH?", category: "compliance",
    excerpt: "REACH is the EU framework for chemical registration, evaluation, and authorization — affecting any chemical substance imported into or manufactured in the European Union.",
    seoDescription: "REACH regulation explained: registration requirements, how it affects laboratory chemical imports into the EU, and SDS implications.",
    content: [{ type: "p", text: "REACH (Registration, Evaluation, Authorisation and Restriction of Chemicals) is the European Union's comprehensive regulation governing how chemical substances are manufactured, imported, and used within the EU. Under REACH, any chemical imported into or manufactured in the EU above 1 tonne per year per registrant must be registered with ECHA (European Chemicals Agency), with registration requirements scaling with volume — higher-volume chemicals require more extensive safety data." }, { type: "h2", text: "What this means for solvent purchasing" }, { type: "p", text: "If you're buying laboratory solvents from a non-EU manufacturer for use in the EU, REACH registration is typically handled by either the importer (you, if importing directly) or by the manufacturer's 'Only Representative' within the EU. Confirming that the solvents you're importing are covered by an active REACH registration avoids the legal risk of importing unregistered substances, which can result in customs holds and regulatory penalties." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-ghs", "what-is-sds"] },
  "what-is-ion-suppression": { slug: "what-is-ion-suppression", title: "What Is Ion Suppression In LC-MS?", h1: "What Is Ion Suppression?", category: "technique",
    excerpt: "Ion suppression reduces your analyte's MS signal because co-eluting contaminants compete for ionization — the single most common cause of unexpected sensitivity loss in LC-MS.",
    seoDescription: "Ion suppression in LC-MS explained: causes, how to detect it, how to compensate with internal standards, and solvent-quality factors.",
    content: [{ type: "p", text: "Ion suppression is a reduction in the analyte's ionization efficiency (and therefore its detected signal) caused by co-eluting matrix components or mobile phase contaminants competing for available charge during the electrospray process. It's the most common mechanism behind the 'matrix effect' concept in LC-MS, and it affects quantitative accuracy directly — a suppressed signal at a given concentration produces a lower response than the calibration predicts, leading to underreported results unless the suppression is detected and compensated for." }, { type: "h2", text: "Solvent as a source of ion suppression" }, { type: "p", text: "Non-volatile residue, trace metal ions, and plasticizer leachates from lower-grade solvents all contribute to the total ionization competition in the electrospray droplet. Upgrading from HPLC grade to LC-MS grade solvent directly reduces this solvent-contributed suppression baseline — it doesn't eliminate matrix-derived suppression from the sample itself, but it removes the solvent's contribution so that only sample matrix effects remain, which are easier to characterize and compensate for with internal standards." }, { type: "product-links", categories: ["lcms-solvents"] }],
    relatedArticles: ["what-is-matrix-effect", "what-is-lcms-grade-solvent", "what-is-internal-standard"] },
  "what-is-column-equilibration": { slug: "what-is-column-equilibration", title: "What Is Column Equilibration?", h1: "What Is Column Equilibration?", category: "definitions",
    excerpt: "Column equilibration is the process of flushing a column with mobile phase until retention behavior stabilizes — essential between gradient runs and after any mobile phase change.",
    seoDescription: "HPLC column equilibration explained: why it's needed, how many column volumes, and what happens when you skip it.",
    content: [{ type: "p", text: "Column equilibration is the process of flushing a chromatographic column with mobile phase at the starting composition until the stationary phase is fully solvated and retention behavior has stabilized — confirmed by consistent retention times across consecutive injections. It's required whenever the column's solvation state has changed: after a gradient run returns to starting conditions, after a mobile phase composition change, after the column has been stored in a different solvent, or when first installing a new column." }, { type: "h2", text: "How much equilibration is enough?" }, { type: "p", text: "A common starting guideline is 5-10 column volumes of equilibration flow at the starting mobile phase composition. For most 150mm × 4.6mm analytical columns at 1 mL/min, that's roughly 8-16 minutes. Some separations — particularly those sensitive to trace-level stationary phase solvation differences — may need more. The practical test is whether retention times for a system suitability standard are stable across consecutive injections; if they're still drifting, equilibration isn't complete yet regardless of how many column volumes have passed." }, { type: "product-links", categories: ["hplc-solvents"] }],
    relatedArticles: ["what-is-gradient-elution", "what-is-system-suitability"] },
  "what-is-blank-subtraction": { slug: "what-is-blank-subtraction", title: "What Is Blank Subtraction?", h1: "What Is Blank Subtraction?", category: "technique",
    excerpt: "Blank subtraction removes the solvent or reagent background from your analytical signal — but only works if the blank actually represents what's behind your sample signal.",
    seoDescription: "Blank subtraction explained: solvent blanks, reagent blanks, method blanks, and when subtraction masks a problem rather than fixing it.",
    content: [{ type: "p", text: "Blank subtraction is the practice of measuring a blank (a sample preparation carried through the complete analytical procedure but without the analyte of interest) and subtracting its signal from the sample signal, to isolate the analyte-attributable portion of the response. Different blank types serve different purposes: a solvent blank checks the mobile phase and injection system, a reagent blank checks all reagents used in sample preparation, and a method blank checks the complete procedure including extraction and cleanup." }, { type: "h2", text: "When blank subtraction masks a problem" }, { type: "p", text: "Blank subtraction is a valid analytical technique, but it shouldn't be used to compensate for a solvent or reagent quality problem that's better solved by upgrading the material itself. If the blank signal is large relative to the analyte signal, the uncertainty of the subtraction itself degrades the final result's precision — the measurement is only as good as the difference between two noisy numbers, which is noisier than either one alone. A cleaner blank (from better-quality solvent or reagent) produces a more reliable result than a contaminated blank mathematically subtracted away." }, { type: "product-links", categories: ["hplc-solvents", "lcms-solvents"] }],
    relatedArticles: ["what-is-limit-of-detection", "what-is-system-suitability"] },
};
